INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('c03e3da90a00c073', 'IA', '["federal"]', 'candidate_eligibility', 'Is there a U.S. Senate race in Iowa for the 2026 cycle?', '["Are Chuck Grassley or Joni Ernst up for re-election in 2026?","When is the next US Senate election in IA?","Is the Iowa US Senate seat an open race?"]', 'Yes. There is an open U.S. Senate race in Iowa in 2026. Incumbent Senator Joni Ernst announced in September 2025 that she will not seek a third term. Senator Chuck Grassley is not on the ballot until 2028.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State – Candidate Information', '2026-05-13', 'volatile', 'official_source_direct', 'Federal candidates and consultants', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('de3b0c365a134088', 'IA', '["state"]', 'candidate_eligibility', 'Is Governor Kim Reynolds running for re-election in 2026?', '["Is the Iowa Governor''s seat open in 2026?","Can Reynolds seek another term?","Iowa 2026 gubernatorial race status"]', 'No. Governor Kim Reynolds announced in April 2025 that she will not seek re-election, making the 2026 gubernatorial race an open seat. This creates a rare scenario of dual open seats for both Governor and U.S. Senate on the same Iowa ballot, the first such occurrence since 1968.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State – Candidate Information', '2026-05-13', 'volatile', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('60a9f376a044847f', 'IA', '["state"]', 'election_dates', 'Which statewide executive offices are up for election in Iowa in 2026?', '["Who is on the state ballot in IA in 2026?","Is the Attorney General up for reelection?","Does Iowa elect a Secretary of Agriculture?"]', 'The statewide executive offices on the 2026 ballot are Governor, Lieutenant Governor, Attorney General, Secretary of State, Auditor of State, Treasurer of State, and Secretary of Agriculture.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State – Election Information', '2026-05-13', 'per_cycle', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('dead872578ef76f9', 'IA', '["state","county","municipal"]', 'finance_ethics', 'Who enforces campaign finance rules in Iowa?', '["Does the Secretary of State handle campaign finance in IA?","Jurisdiction of the IECDB in Iowa","Where do I file campaign finance reports?"]', 'Campaign finance in Iowa is administered and enforced by the Iowa Ethics and Campaign Disclosure Board (IECDB), which operates entirely separately from the Secretary of State''s election administration functions.', 'https://ethics.iowa.gov/', 'Iowa Ethics and Campaign Disclosure Board', '2026-05-13', 'static', 'official_source_direct', 'Candidates and Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('29acdfb8db9e019b', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What is the threshold for registering a candidate campaign committee with the IECDB?', '["When do I have to register a campaign committee in IA?","IECDB registration dollar limit","How much can I spend before filing a committee?"]', 'A candidate must register a campaign committee with the IECDB within 10 days of receiving contributions, making expenditures, or incurring loans aggregating more than $1,000.', 'https://ethics.iowa.gov/frequently-asked-questions/campaign-finance-faqs', 'IECDB – Campaign Finance FAQs', '2026-05-13', 'static', 'official_source_direct', 'All state and local candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('38f8e18b9f4d1f2c', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What are the individual contribution limits for state and local candidates in Iowa?', '["How much can an individual give to a Governor candidate in IA?","Statewide contribution limits Iowa","Does Iowa have campaign donation caps?"]', 'Iowa has NO contribution limits for state and local candidates. Candidates running for state or local office may receive unlimited funds from individuals and PACs, provided the contributions are properly disclosed.', 'https://ethics.iowa.gov/frequently-asked-questions/campaign-finance-faqs', 'IECDB – Campaign Finance FAQs', '2026-05-13', 'static', 'official_source_direct', 'Candidates and donors', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('8c69c3c106b1d819', 'IA', '["state","county","municipal"]', 'finance_ethics', 'Can labor unions contribute directly to a candidate from their general treasury in Iowa?', '["Are union dues contributions legal in IA?","Labor union donation rules Iowa","Do unions have to use a PAC?"]', 'Yes. Unlike corporations and financial institutions, labor unions are NOT included in the direct contribution prohibitions outlined in Iowa Code § 68A.503. Labor unions may make unlimited direct contributions from their general treasuries to state and local candidates in Iowa.', 'https://www.legis.iowa.gov/docs/code/68A.503.pdf', 'Iowa Code § 68A.503', '2026-05-13', 'static', 'statute_citation', 'Unions and Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('7544e608e4acf988', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Is a photo ID required to vote in person in Iowa?', '["Iowa voter ID laws","Do I need my driver''s license to vote in IA?","Poll ID requirements Iowa"]', 'Yes. Since 2017, Iowa law requires a valid photo ID to vote. Acceptable forms include an Iowa driver''s license, Iowa non-operator ID, U.S. passport, U.S. military or veteran ID, tribal ID, or an Iowa Voter ID Card.', 'https://sos.iowa.gov/voters/voterid', 'Iowa Secretary of State – Voter ID', '2026-05-13', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('ff27f3cd67b7bb13', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How does a voter get an ID if they do not have a driver''s license in Iowa?', '["Iowa Voter ID Card mechanism","Free voting ID Iowa","Voting without a driver''s license IA"]', 'Registered voters who do not have an Iowa driver''s license or non-operator ID are automatically mailed an Iowa Voter ID Card for free by their county auditor. This card contains a 4-digit PIN used for voting and requesting absentee ballots.', 'https://sos.iowa.gov/voters/voterid', 'Iowa Secretary of State – Voter ID', '2026-05-13', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('42f564f49aded74e', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can someone vote in Iowa if they forgot their photo ID?', '["Attesting voter mechanism IA","Voting without ID at polls Iowa","Can another voter vouch for my identity?"]', 'Yes, a voter without ID can have another registered voter from the same precinct attest to their identity. The attesting voter must provide their own valid ID and can only attest for up to two people per election. Alternatively, the voter can cast a provisional ballot.', 'https://sos.iowa.gov/voters/voterid', 'Iowa Secretary of State – Voter ID', '2026-05-13', 'static', 'official_source_direct', 'Voters and Poll Watchers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('1c0a824931306004', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the voter registration deadline in Iowa?', '["When is the last day to register to vote in IA?","15-day registration rule Iowa","Does Iowa have same-day registration?"]', 'The pre-registration deadline is 15 days before the election. However, Iowa offers same-day registration, allowing eligible citizens to register and vote simultaneously at their polling place on Election Day or during in-person early voting.', 'https://sos.iowa.gov/voters/election-day', 'Iowa Secretary of State – Election Day Registration', '2026-05-13', 'static', 'official_source_direct', 'Unregistered voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('450ced15ef46dc72', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'How many days of early voting are available in Iowa?', '["When does early voting start in IA?","20-day early voting window Iowa","Iowa in-person absentee duration"]', 'Iowa offers a 20-day window for in-person early absentee voting. Voters can cast their ballots at the county auditor''s office or designated satellite locations during this period leading up to Election Day.', 'https://sos.iowa.gov/voters/absentee-voting', 'Iowa Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'All voters and GOTV operations', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('01ba48516470538b', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the deadline for an absentee ballot to be returned and counted in Iowa?', '["When is my absentee ballot due in IA?","Iowa mail ballot postmark rule","Election Day 8pm ballot receipt"]', 'Absentee ballots must be physically received by the county auditor''s office by 8:00 p.m. on Election Day. Iowa does not have a postmark grace period; ballots arriving after the polls close are rejected.', 'https://sos.iowa.gov/voters/absentee-voting', 'Iowa Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'Absentee voters and Campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('903b3f812a36e1e7', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Do I need an ID number to request an absentee ballot in Iowa?', '["Iowa absentee ballot request requirements","Voter PIN for mail ballot IA","Can I request a mail ballot without a driver''s license?"]', 'Yes. An absentee ballot request form must include a Voter Verification Number. This can be an Iowa driver''s license or non-operator ID number, or the 4-digit PIN located on the voter''s free Iowa Voter ID Card.', 'https://sos.iowa.gov/voters/absentee-voting', 'Iowa Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'Absentee voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('cca250bca9519184', 'IA', '["federal","state","county","municipal","judicial"]', 'candidate_eligibility', 'Can a person with a felony conviction vote in Iowa?', '["Felon voting rights IA","Voting post-incarceration rules Iowa","Executive order felony voting restoration"]', 'Yes. Under a 2020 Executive Order issued by Governor Kim Reynolds, voting rights are automatically restored to most individuals with felony convictions upon completion of their sentence, including probation and parole. Certain violent felonies, like homicide, require an individual application to the Governor.', 'https://governor.iowa.gov/services/voting-rights-restoration', 'Iowa Governor''s Office – Voting Rights Restoration', '2026-05-13', 'static', 'official_source_direct', 'All eligible citizens', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('618f64718438cd89', 'IA', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Iowa Primary Election?', '["What date is the IA primary in 2026?","Iowa June primary date","When do polls open for the IA primary?"]', 'The Iowa Primary Election is held on Tuesday, June 2, 2026. State law mandates the primary for the first Tuesday in June in even-numbered years.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State – Candidate Information', '2026-05-13', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('88d213bad2b54da9', 'IA', '["federal","state","county","municipal","judicial"]', 'election_dates', 'When is the 2026 Iowa General Election?', '["What date is the IA general election in 2026?","Iowa 2026 midterm election date","When is Election Day 2026 in Iowa?"]', 'The Iowa General Election is scheduled for Tuesday, November 3, 2026.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State – Candidate Information', '2026-05-13', 'per_cycle', 'official_source_direct', 'All candidates and voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('1ce5470274f5248b', 'IA', '["federal","state","county"]', 'filing_requirements', 'When was the candidate filing deadline for the 2026 Iowa primary?', '["When did candidates have to file for the 2026 primary in Iowa?","Declaration of candidacy deadline 2026","Iowa March filing deadline"]', 'The filing deadline for major party candidates to appear on the June primary ballot was March 13, 2026. This date marks the close of the filing window, which legally concludes 81 days prior to the primary.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State – Candidate Information', '2026-05-13', 'per_cycle', 'official_source_direct', 'Major party candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('feffbc1d26bf8a55', 'IA', '["federal","state"]', 'redistricting', 'Who draws the congressional and legislative maps in Iowa?', '["Iowa redistricting commission","How are districts drawn in Iowa?","Legislative Services Agency LSA redistricting"]', 'Iowa utilizes a distinctive non-partisan redistricting process. The Legislative Services Agency (LSA), a nonpartisan staff agency, draws the maps without analyzing political data, election results, or incumbent addresses. The legislature must vote on the LSA''s first two proposed plans up or down without amendments.', 'https://www.legis.iowa.gov/legislators/redistricting', 'Iowa Legislature – Redistricting', '2026-05-13', 'static', 'official_source_direct', 'Federal and state legislative candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('2e4d4c0bc262776c', 'IA', '["federal","state"]', 'redistricting', 'How many congressional and legislative districts does Iowa have?', '["Number of US House seats in IA","Iowa legislative district structure","How many state senators in Iowa?"]', 'Iowa is apportioned 4 U.S. House districts. The state legislature consists of 50 State Senate districts and 100 State House districts. The maps are nested, meaning every State Senate district contains exactly two State House districts.', 'https://www.legis.iowa.gov/legislators/redistricting', 'Iowa Legislature – Redistricting', '2026-05-13', 'static', 'official_source_direct', 'Federal and state legislative candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('2ee28ad2582237c9', 'IA', '["judicial"]', 'election_dates', 'Are judges elected in partisan elections in Iowa?', '["Missouri Plan Iowa judicial selection","Are there primary elections for judges in IA?","Iowa Supreme Court retention elections"]', 'No. Iowa uses a merit-based selection system (the Missouri Plan). The State Judicial Nominating Commission nominates candidates, the Governor appoints them, and judges subsequently face periodic yes/no retention elections during general elections, rather than contested partisan elections.', 'https://www.iowacourts.gov/for-the-public/educational-resources-and-services/iowa-courts-history/merit-selection-in-iowa', 'Iowa Judicial Branch – Merit Selection', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('c726210c355f7a1b', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What are the voting hours on Election Day in Iowa?', '["When do polls open and close in IA?","Iowa election day voting hours","What time do polls close on Election Day?"]', 'Polling places in Iowa are open from 7:00 a.m. to 8:00 p.m. on Election Day. Any voter who is in line at the polling place by 8:00 p.m. is legally permitted to cast their ballot.', 'https://sos.iowa.gov/voters/election-day', 'Iowa Secretary of State – Election Day', '2026-05-13', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('005ce8e5b19b1eb0', 'IA', '["state","county","municipal"]', 'finance_ethics', 'Can a corporation or financial institution contribute directly to a candidate for office in Iowa?', '["Are corporate contributions legal in IA?","Can my business donate to a state candidate?","Is there a ban on bank or insurance company donations in Iowa?"]', 'No. Under Iowa Code § 68A.503, it is illegal for any for-profit or nonprofit corporation, bank, savings and loan association, credit union, or insurance company to make a direct monetary or in-kind contribution to a candidate. These entities may only participate in political activity through a separate, registered PAC (Political Action Committee).', 'https://www.legis.iowa.gov/docs/code/68A.503.pdf', 'Iowa Code § 68A.503', '2026-05-13', 'static', 'statute_citation', 'Corporations, Financial Institutions, and Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('cb649f635d46de30', 'IA', '["state"]', 'finance_ethics', 'What is the legislative session contribution ban in Iowa?', '["Lobbyist session ban IA","When are contributions banned for state reps?","Blackout period for donations Iowa"]', 'Under Iowa Code § 68A.504, state legislators and statewide executive candidates cannot solicit or accept contributions from lobbyists or PACs during the regular legislative session (12:00 a.m. first day through 11:59 p.m. sine die). For the Governor and gubernatorial candidates, the ban extends 30 days post-session; exceptions exist for federal accounts, statutory political committees, and special elections.', 'https://www.legis.iowa.gov/docs/code/68A.504.pdf', 'Iowa Code § 68A.504', '2026-05-13', 'static', 'statute_citation', 'State candidates, Lobbyists, and PACs', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('c48f50ded8e2a5f4', 'IA', '["state","county","municipal","judicial"]', 'recall_rules', 'Can voters recall the Governor or state legislators in Iowa?', '["Statewide recall mechanism IA","How to recall a state official in Iowa","Does Iowa allow for the removal of politicians by petition?"]', 'No. Neither the Iowa Constitution nor the Iowa Code provides a mechanism for the recall of statewide elected officials or members of the General Assembly. While some Iowa cities may have local recall provisions under their specific municipal home rule charters, state-level officials are not subject to recall.', 'https://www.legis.iowa.gov/docs/code/39.pdf', 'Iowa Code Chapter 39 / Iowa Constitution', '2026-05-13', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('9d8ad059f19323ec', 'IA', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Iowa State Senate?', '["How old to run for State Senate IA?","District residency for IA Senate candidates","Qualifications for Iowa State Senator"]', 'Under Iowa Constitution Article III § 5, a candidate for the State Senate must be at least 25 years of age, a U.S. citizen, and a resident of the state for one year. Crucially, they must have resided in the specific district they seek to represent for at least 60 days prior to the election.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article III § 5', '2026-05-13', 'static', 'statute_citation', 'State Senate candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('5c2b127a2ca8ca8d', 'IA', '["state"]', 'candidate_eligibility', 'What are the age and residency requirements to run for the Iowa State House?', '["How old to run for State Representative IA?","District residency for IA House candidates","Qualifications for Iowa State Representative"]', 'Under Iowa Constitution Article III § 4, a candidate for the State House of Representatives must be at least 21 years of age, a U.S. citizen, and a resident of the state for one year. They must have resided in the specific district for at least 60 days prior to the election.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article III § 4', '2026-05-13', 'static', 'statute_citation', 'State House candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('13f8b93bb990f06c', 'IA', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Governor of Iowa?', '["How old do you have to be to be IA Governor?","Gubernatorial residency requirement Iowa","Qualifications for Governor IA"]', 'Under Iowa Constitution Article IV § 6, a candidate for Governor must be at least 30 years old and a citizen of the United States. Additionally, the candidate must have been a resident of Iowa for at least two years immediately preceding the election.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article IV § 6', '2026-05-13', 'static', 'statute_citation', 'Gubernatorial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('f3390fec3b55918f', 'IA', '["judicial"]', 'candidate_eligibility', 'What are the qualifications to serve on the Iowa Supreme Court?', '["How old to be a judge in Iowa?","Do Supreme Court justices have to be lawyers in IA?","Qualifications for IA Supreme Court"]', 'A candidate for the Iowa Supreme Court must be a member of the Iowa bar and at least 35 years of age at the time of appointment. Under Iowa Code § 46.14, justices must also be residents of the state and have practiced law for a minimum of five years.', 'https://www.legis.iowa.gov/docs/code/46.14.pdf', 'Iowa Code § 46.14', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('82b25551010392cf', 'IA', '["state"]', 'election_dates', 'How are vacancies in the Iowa General Assembly filled?', '["Special election for State Assembly IA","How is a vacant state senate seat filled in Iowa?","Legislative vacancy procedure IA"]', 'Legislative vacancies in Iowa are filled strictly by special election called by Governor proclamation under Iowa Code § 69.14. There is no provision for interim appointments by the Governor or county boards for these seats.', 'https://www.legis.iowa.gov/docs/code/69.14.pdf', 'Iowa Code § 69.14', '2026-05-13', 'static', 'statute_citation', 'State Legislative candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('aa970250a2e7412e', 'IA', '["judicial"]', 'election_dates', 'How are mid-term vacancies filled in the Iowa court system?', '["Who appoints judges in Iowa?","Judicial vacancy fill process IA","Role of the State Judicial Nominating Commission"]', 'When a judicial vacancy occurs, the State Judicial Nominating Commission (for Supreme Court and Appeals) or District Nominating Commission provides a list of nominees to the Governor. Under Iowa Constitution Art. V § 16, the Governor must appoint one of the nominees within 30 days.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article V § 16', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates and legal counsel', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('52ac61e011d98144', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the process for curing a mail ballot signature error in Iowa?', '["When do I have to fix my signature for my mail ballot?","Absentee ballot curing window IA","Iowa mail ballot signature mismatch"]', 'If an absentee ballot envelope is found to have a signature deficiency or mismatch, the county auditor must notify the voter within 24 hours. Under Iowa Code § 53.31, the voter has until the close of business on the Monday before Election Day to cure the defect in person.', 'https://www.legis.iowa.gov/docs/code/53.31.pdf', 'Iowa Code § 53.31', '2026-05-13', 'static', 'statute_citation', 'Voters and Campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('0b528d6f2b1197de', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Under what circumstances is a provisional ballot used in Iowa?', '["When do I have to cast a provisional ballot?","Iowa provisional ballot rules","Voting if my ID is missing at the polls"]', 'Provisional ballots are issued if a voter''s eligibility cannot be immediately confirmed, most commonly due to a lack of required photo ID. Under Iowa Code § 49.81, the ballot is counted only if the voter provides ID or cures the residency issue at the county auditor''s office by the set deadline.', 'https://www.legis.iowa.gov/docs/code/49.81.pdf', 'Iowa Code § 49.81', '2026-05-13', 'static', 'statute_citation', 'Voters and Poll Watchers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('c523321db533aff0', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'What is the electioneering buffer zone at Iowa polling places?', '["How close to the door can I campaign in IA?","300-foot rule Iowa voting","Campaign signs at polling places IA"]', 'Iowa enforces a 300-foot electioneering buffer zone measured from any outside door of a building containing a polling place. Under Iowa Code § 39A.4(1)(a)(3), distributing literature or soliciting votes within this boundary is a criminal offense.', 'https://www.legis.iowa.gov/docs/code/39A.4.pdf', 'Iowa Code § 39A.4', '2026-05-13', 'static', 'statute_citation', 'Campaigns and Poll Workers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('33c7f1764c2c812a', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Can 17-year-olds vote in a partisan primary in Iowa?', '["Voting in primary if 17 IA","Underage primary voting rules Iowa","Do I have to be 18 to vote in the June primary?"]', 'Yes. Under Iowa Code § 48A.5, a 17-year-old who will be 18 years of age on or before the date of the general election is permitted to register and vote in the preceding primary election.', 'https://www.legis.iowa.gov/docs/code/48A.5.pdf', 'Iowa Code § 48A.5(2)(c)(2)', '2026-05-13', 'static', 'statute_citation', 'Young voters and Campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('bb4ab58026dc0588', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Iowa law require employers to grant time off to vote?', '["Do I get paid time off to vote in IA?","Employee voting leave Iowa","3 hours off to vote rule Iowa"]', 'Yes. Under Iowa Code § 49.109, any employee who does not have three consecutive non-working hours while the polls are open is entitled to three hours of paid leave to vote. The employee must request this leave in writing from their employer before Election Day.', 'https://www.legis.iowa.gov/docs/code/49.109.pdf', 'Iowa Code § 49.109', '2026-05-13', 'static', 'statute_citation', 'Voters and Employers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('6423707311054595', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What is the itemized disclosure threshold for individual campaign contributions in Iowa?', '["When do I have to list a donor''s name in IA?","Campaign contribution disclosure limit Iowa","Iowa $25 donation rule"]', 'Iowa has one of the lowest itemization thresholds in the nation. Under Iowa Code § 68A.402, campaign committees must individually itemize every contribution that exceeds $25 in aggregate from a single contributor in a calendar year.', 'https://www.legis.iowa.gov/docs/code/68A.402.pdf', 'Iowa Code § 68A.402', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('b65ce023d8addfb1', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What is the limit for anonymous campaign contributions in Iowa?', '["Can I donate cash anonymously in IA?","Anonymous contribution cap Iowa","Passing the hat rules Iowa campaign finance"]', 'Anonymous contributions are strictly limited to $25 or less per contributor. Under Iowa Code § 68A.501, any anonymous contribution exceeding $25 is prohibited and must be remitted to the state''s general fund or a charitable organization.', 'https://www.legis.iowa.gov/docs/code/68A.501.pdf', 'Iowa Code § 68A.501', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('cec71bad5d9c8a5b', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What is the reporting requirement for Independent Expenditures in Iowa?', '["When does an independent group have to file in IA?","Independent expenditure threshold Iowa","48-hour IE reporting rule"]', 'Any person or group making independent expenditures aggregating more than $1,000 in a calendar year must file an Independent Expenditure Report. Under Iowa Code § 68A.404, this report must be filed electronically within 48 hours of the expenditure.', 'https://www.legis.iowa.gov/docs/code/68A.404.pdf', 'Iowa Code § 68A.404', '2026-05-13', 'static', 'statute_citation', 'Super PACs and Independent Expenditure Committees', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('a781d17510b506a2', 'IA', '["state","county","municipal"]', 'finance_ethics', 'Are candidates prohibited from using their campaign consultants for independent expenditures in Iowa?', '["IA consultant cooling off period","Independent expenditure coordination rules Iowa","6-month lookback rule Iowa"]', 'Yes. To prevent illegal coordination, Iowa Code § 68A.404(7) prohibits a person making an independent expenditure from employing a consultant who has provided services to the candidate for the same office within the preceding six months.', 'https://www.legis.iowa.gov/docs/code/68A.404.pdf', 'Iowa Code § 68A.404(7)', '2026-05-13', 'static', 'statute_citation', 'Campaign Consultants and Super PACs', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('0434f8a5173e8f68', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What are the rules for disposing of surplus campaign funds in Iowa?', '["Surplus funds disposition IA","Can I give my leftover campaign money to charity in Iowa?","What happens to campaign money when I close my committee?"]', 'Surplus campaign funds cannot be converted to personal use. Under Iowa Code § 68A.303, funds may be returned to contributors, transferred to a political party, donated to a charitable organization, or used for the candidate''s next campaign.', 'https://www.legis.iowa.gov/docs/code/68A.303.pdf', 'Iowa Code § 68A.303', '2026-05-13', 'static', 'statute_citation', 'Candidates concluding campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('49064f641207a44c', 'IA', '["federal","state","county"]', 'filing_requirements', 'What is the filing deadline for non-partisan or independent candidates for the 2026 general election in Iowa?', '["When must independent candidates file in IA?","Iowa non-partisan candidate deadline","August filing deadline Iowa"]', 'Candidates nominated by petition (Independents) or by non-party political organizations for the general election must file their paperwork between early and mid-August. For the 2026 cycle, the deadline is August 14 at 5:00 p.m.', 'https://sos.iowa.gov/elections/pdf/2026/2026calendar.pdf', 'Iowa Secretary of State – 2026 Elections Calendar', '2026-05-13', 'per_cycle', 'official_source_direct', 'Independent and non-party candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('5c64c398907c1cd1', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Does Iowa have a postmark grace period for mail ballots?', '["Iowa mail ballot postmark rule","When is the latest my ballot can arrive in IA?","Absentee ballot receipt deadline"]', 'No. Iowa has no postmark grace period. To be counted, an absentee ballot must be physically received by the county auditor''s office before the polls close at 8:00 p.m. on Election Day.', 'https://sos.iowa.gov/voters/absentee-voting', 'Iowa Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'All voters and Campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('21ceceb40cfc027b', 'IA', '["federal","state","county","municipal","judicial"]', 'runoff_rules', 'What triggers an automatic or state-funded recount in Iowa?', '["Automatic recount margin Iowa","When is a recount required by law in IA?","Recount request threshold IA"]', 'Under Iowa Code § 50.48, any candidate can request a recount. The state or county pays for it only if the margin between the winning and losing candidate is less than 50 votes or less than 1% of the total votes cast for the office, whichever is greater. If the margin is wider, the requesting candidate pays a bond, refunded only if the recount changes the outcome.', 'https://www.legis.iowa.gov/docs/code/50.48.pdf', 'Iowa Code § 50.48(1)', '2026-05-13', 'static', 'statute_citation', 'Candidates and Legal Counsel', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('72f61c8d147b88b3', 'IA', '["federal"]', 'election_dates', 'How are vacancies in the U.S. Senate filled in Iowa?', '["Who replaces a US Senator from Iowa?","Does the Governor appoint Senate vacancies in IA?","Special election for US Senate Iowa"]', 'Under Iowa Code § 69.13, if a U.S. Senate seat becomes vacant, the Governor appoints a temporary replacement. This appointee serves until the vacancy is filled by a special election, which is held concurrently with the next pending regular election (provided the vacancy occurs at least 89 days prior).', 'https://www.legis.iowa.gov/docs/code/69.13.pdf', 'Iowa Code § 69.13', '2026-05-13', 'static', 'statute_citation', 'Federal candidates and consultants', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('5d2b007c9d824baf', 'IA', '["judicial"]', 'election_dates', 'How are the members of the State Judicial Nominating Commission appointed in Iowa?', '["State Judicial Nominating Commission composition","2019 Iowa judicial reform","Who picks the commissioners for Iowa judges?"]', 'Under Iowa Code § 46.1, following a 2019 reform, the State Judicial Nominating Commission consists of 17 members: 8 lawyers elected by resident members of the Iowa bar, and 9 lay members appointed by the Governor. This structure removed the Supreme Court justice as chair and granted the Governor majority appointment power.', 'https://www.legis.iowa.gov/docs/code/46.1.pdf', 'Iowa Code § 46.1', '2026-05-13', 'static', 'statute_citation', 'Judicial candidates and legal counsel', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('6de7c5a4af07bea3', 'IA', '["federal"]', 'candidate_eligibility', 'What are the age and residency requirements to run for U.S. House in Iowa?', '["Do I have to live in the district to run for Congress in IA?","Congressional age limit Iowa","US House qualifications"]', 'Under the U.S. Constitution, a candidate for the U.S. House of Representatives must be at least 25 years old, a U.S. citizen for seven years, and an inhabitant of Iowa when elected. District residency is not constitutionally required.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State / U.S. Constitution Art. I § 2', '2026-05-13', 'static', 'official_source_direct', 'U.S. House candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('eff8799b960eb0bd', 'IA', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Lieutenant Governor in Iowa?', '["How old do you have to be to be IA Lt Governor?","Lieutenant Governor residency requirement Iowa","Qualifications for Lt Gov IA"]', 'Under Iowa Constitution Article IV § 6, the qualifications for Lieutenant Governor are identical to the Governor: the candidate must be at least 30 years old, a citizen of the United States, and a resident of Iowa for at least two years immediately preceding the election.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article IV § 6', '2026-05-13', 'static', 'statute_citation', 'Lieutenant Gubernatorial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('e69e42332f9ccab8', 'IA', '["state"]', 'candidate_eligibility', 'What are the qualifications to run for Attorney General, Secretary of State, Auditor, or Treasurer in Iowa?', '["Do I have to be a lawyer to be AG in IA?","Statewide executive residency rules Iowa","Qualifications for Secretary of State IA"]', 'While the Iowa Constitution broadly requires statewide executive officers to be qualified electors (18 years old and an Iowa resident), the Attorney General must specifically be authorized to practice law in Iowa in order to legally perform the statutory duties outlined in Iowa Code § 13.2.', 'https://www.legis.iowa.gov/docs/code/13.2.pdf', 'Iowa Code § 13.2', '2026-05-13', 'static', 'statute_citation', 'Statewide executive candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('edb4aef33c9c3a34', 'IA', '["state"]', 'election_dates', 'What is the role of the Iowa Secretary of Agriculture?', '["Does Iowa elect a Secretary of Agriculture?","Statewide agricultural office Iowa","Is the Ag Secretary appointed in IA?"]', 'The Iowa Secretary of Agriculture is a distinctive 7th statewide elected executive officer. Serving a four-year term, the Secretary heads the Iowa Department of Agriculture and Land Stewardship (IDALS) and is elected during the midterm cycle alongside the Governor.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State', '2026-05-13', 'static', 'official_source_direct', 'Statewide candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1')
INSERT INTO campaign_reference (id, state, office_level, category, question, question_variants, answer, source_url, source_name, last_verified_date, update_frequency, verification_method, scope, import_batch_id) VALUES
  ('97656e9119287bea', 'IA', '["judicial"]', 'election_dates', 'What are the term lengths for justices on the Iowa Supreme Court?', '["How long do Supreme Court justices serve in IA?","Iowa Supreme Court retention elections","Supreme Court structure Iowa"]', 'The Iowa Supreme Court consists of seven justices. Following their initial appointment and first retention election, justices serve eight-year terms before facing another yes/no retention vote at a general election.', 'https://www.iowacourts.gov/iowa-courts/supreme-court/', 'Iowa Judicial Branch', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('e07e65836a09005d', 'IA', '["judicial"]', 'election_dates', 'What are the term lengths for judges on the Iowa Court of Appeals?', '["How long do appellate judges serve in IA?","Iowa Court of Appeals retention","Appellate court structure Iowa"]', 'The Iowa Court of Appeals consists of nine judges. After their initial appointment and first retention election, they serve six-year terms before facing subsequent yes/no retention elections.', 'https://www.iowacourts.gov/iowa-courts/court-of-appeals/', 'Iowa Judicial Branch', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('77af70d19a9921a7', 'IA', '["judicial"]', 'election_dates', 'What are the term lengths for District Court judges in Iowa?', '["How long do trial judges serve in IA?","Iowa District Court retention elections","Trial court term limits Iowa"]', 'Iowa District Court judges serve six-year terms following their initial appointment and first retention election. They must stand for a yes/no retention vote to remain in office.', 'https://www.iowacourts.gov/iowa-courts/district-court/', 'Iowa Judicial Branch', '2026-05-13', 'static', 'official_source_direct', 'Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('f8253b81dc4ea4f8', 'IA', '["judicial"]', 'election_dates', 'What was the outcome of the 2010 Iowa Supreme Court retention election?', '["Varnum v Brien retention election","Did Iowa voters unseat Supreme Court justices?","Same-sex marriage ruling judges Iowa"]', 'In a highly distinctive historical event for states using merit selection, three Iowa Supreme Court justices were unseated in the 2010 retention election. Voters removed them following a targeted campaign responding to the Court''s unanimous ''Varnum v. Brien'' decision legalizing same-sex marriage.', 'https://www.iowacourts.gov/for-the-public/educational-resources-and-services/iowa-courts-history/merit-selection-in-iowa', 'Iowa Judicial Branch', '2026-05-13', 'static', 'secondary_source', 'Campaign strategists and Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('290251d160b55df7', 'IA', '["judicial"]', 'voter_interaction', 'What is the ballot format for a judicial retention election in Iowa?', '["How do judges appear on the ballot in IA?","Retention ballot question wording","Are judges opposed on the ballot in Iowa?"]', 'Judicial retention elections do not feature competing candidates. Voters are presented with a simple binary question for each judge: ''Shall Judge [Name] be retained in office?'' with ''Yes'' and ''No'' options.', 'https://sos.iowa.gov/elections/voterinformation/judgeretention.html', 'Iowa Secretary of State – Judge Retention', '2026-05-13', 'static', 'official_source_direct', 'Voters and Judicial candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('de3a5f7720c5ca6f', 'IA', '["federal"]', 'election_dates', 'How are vacancies in the U.S. House of Representatives filled in Iowa?', '["Special election for Congress IA","Does the Governor appoint US House vacancies in Iowa?","Congressional vacancy fill procedure"]', 'Vacancies in the U.S. House of Representatives are filled exclusively by a special election called by the Governor via proclamation under Iowa Code § 69.14. The Governor cannot appoint an interim Representative.', 'https://www.legis.iowa.gov/docs/code/69.14.pdf', 'Iowa Code § 69.14', '2026-05-13', 'static', 'statute_citation', 'Federal candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('00604fefb42b0cdd', 'IA', '["state"]', 'election_dates', 'Who succeeds the Governor of Iowa in the event of a vacancy?', '["What happens if the IA Governor resigns?","Lieutenant Governor succession Iowa","Gubernatorial vacancy fill"]', 'If the Governor dies, resigns, or is removed, the Lieutenant Governor becomes the Governor for the remainder of the unexpired term under Iowa Constitution Article IV § 17.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article IV § 17', '2026-05-13', 'static', 'statute_citation', 'Statewide officials', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('f6572a37ffdd90a7', 'IA', '["state"]', 'election_dates', 'How are vacancies filled for Iowa''s Attorney General, Secretary of State, Auditor, Treasurer, or Secretary of Agriculture?', '["Does the Governor appoint the AG in IA?","Vacancy fill for statewide executive offices","Who replaces the State Treasurer?"]', 'If a vacancy occurs in a statewide executive office (Attorney General, Secretary of State, Auditor, Treasurer, or Secretary of Agriculture), the Governor appoints a replacement to serve until the vacancy can be filled at the next pending general election under Iowa Code § 69.8.', 'https://www.legis.iowa.gov/docs/code/69.8.pdf', 'Iowa Code § 69.8', '2026-05-13', 'static', 'statute_citation', 'Statewide executive officials', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('2847d2c23fd9350b', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'When does the absentee ballot request window open in Iowa?', '["When can I request a mail ballot in IA?","70-day absentee request window","How early can I apply for an absentee ballot?"]', 'Voters in Iowa may begin submitting absentee ballot request forms to their county auditor 70 days before the election. The request form must be physically received by the auditor''s office no later than 5:00 p.m. on the 15th day before the election.', 'https://sos.iowa.gov/voters/absentee-voting', 'Iowa Secretary of State – Absentee Voting', '2026-05-13', 'static', 'official_source_direct', 'All voters', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('95d2dd6662215b73', 'IA', '["federal","state","county","municipal","judicial"]', 'voter_interaction', 'Are secure drop boxes for absentee ballots legally permitted in Iowa?', '["Can I put my absentee ballot in a drop box in IA?","Mail ballot drop boxes Iowa","Does Iowa use drop boxes for voting?"]', 'Yes, but they are strictly limited. Under Iowa law (SF 413), a county may establish only one secure drop box, and it must be located on the property surrounding the county auditor''s office under continuous video surveillance.', 'https://www.legis.iowa.gov/docs/publications/LGE/89/SF413.pdf', 'Iowa SF 413', '2026-05-13', 'static', 'statute_citation', 'Voters and Election Officials', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('922ea27716b9b4f9', 'IA', '["federal","state","county","municipal","judicial"]', 'finance_ethics', 'What is the Verified Statement of Registration (VSR) requirement in Iowa?', '["Out of state PAC registration IA","Federal committee reporting Iowa","VSR filing deadline"]', 'Under Iowa Code § 68A.201A, any federal or out-of-state political committee that contributes more than $50 to an Iowa candidate or committee must file a Verified Statement of Registration (VSR) with the IECDB within 15 days of making the contribution.', 'https://www.legis.iowa.gov/docs/code/68A.201A.pdf', 'Iowa Code § 68A.201A', '2026-05-13', 'static', 'statute_citation', 'Federal PACs and Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('12acc61fa01ad9b6', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What are the standard campaign finance reporting periods in Iowa?', '["When are campaign finance reports due in IA?","Reporting calendar specifics Iowa","January 19 annual report"]', 'In an election year, a candidate committee files standard disclosure reports on May 19 (pre-primary), July 19 (post-primary), October 19 (pre-general), and an annual report on January 19. Supplemental reports may be required depending on election timing.', 'https://ethics.iowa.gov/frequently-asked-questions/campaign-finance-faqs', 'IECDB – Reporting Deadlines', '2026-05-13', 'static', 'official_source_direct', 'Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('edea1e08ac52a352', 'IA', '["state","county","municipal"]', 'finance_ethics', 'What are the penalties for filing a campaign finance report late with the IECDB?', '["Late filing fees IA","How much is the fine for missing a reporting deadline?","IECDB late penalties"]', 'Under Iowa Code § 68A.701, the IECDB assesses automatic escalating civil penalties for late reports. The base penalty typically begins at $20 and escalates to $50, $100, and $200 depending on the number of days the report is delinquent and the committee type.', 'https://www.legis.iowa.gov/docs/code/68A.701.pdf', 'Iowa Code § 68A.701', '2026-05-13', 'static', 'statute_citation', 'Campaign Treasurers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('619342c3f6a42ea9', 'IA', '["federal","state","county","municipal"]', 'finance_ethics', 'What are the disclosure requirements for print advertising and yard signs in Iowa?', '["Do mailers need an ''Ad paid for by'' disclaimer?","Attribution statements Iowa","Yard sign disclaimer requirements"]', 'Any published political material designed to influence an election must include an explicit ''Paid for by'' attribution statement. Under Iowa Code § 68A.405, this statement must clearly identify the name and address of the person or committee paying for the material.', 'https://www.legis.iowa.gov/docs/code/68A.405.pdf', 'Iowa Code § 68A.405', '2026-05-13', 'static', 'statute_citation', 'All Campaigns and Printers', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('dbaeca081e2bf4b1', 'IA', '["federal","state","county","municipal"]', 'voter_interaction', 'What are the state restrictions on placing campaign signs in public areas in Iowa?', '["Can I put political signs on state roads?","Right-of-way yard sign rules IA","Where are campaign signs prohibited in Iowa?"]', 'Under Iowa Code § 68A.406, it is illegal to place campaign signs within the public right-of-way along highways and streets. It is also illegal to place campaign signs on corporate property without explicit permission from the property owner.', 'https://www.legis.iowa.gov/docs/code/68A.406.pdf', 'Iowa Code § 68A.406', '2026-05-13', 'static', 'statute_citation', 'All campaigns', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('4e15954ff7059abc', 'IA', '["state"]', 'redistricting', 'How do State Senate and State House districts overlap in Iowa?', '["Nesting requirement Iowa redistricting","How many house seats are in a senate district?","IA legislative district structure"]', 'Iowa utilizes a strict ''nesting'' requirement in its redistricting maps. Each of the 50 State Senate districts is divided exactly in half to create two State House districts, totaling 100 House districts.', 'https://www.legis.iowa.gov/legislators/redistricting', 'Iowa Legislature – Redistricting', '2026-05-13', 'static', 'official_source_direct', 'State Legislative candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('671bb42c100984d3', 'IA', '["state"]', 'election_dates', 'What is the structure of the Iowa General Assembly''s legislative session?', '["Does the Iowa legislature meet every year?","Annual legislative session IA","Is there a day limit on the Iowa session?"]', 'The Iowa General Assembly meets annually. There is no strict constitutional cap on the number of days the legislature can meet, but per diem expenses are only paid for 110 days in odd-numbered years and 100 days in even-numbered years, practically concluding the session by late April or May.', 'https://www.legis.iowa.gov/agencies/nonpartisan/lsa', 'Iowa Legislative Services Agency', '2026-05-13', 'static', 'official_source_direct', 'State Legislators and Consultants', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('f4ece920d2f8963e', 'IA', '["state"]', 'ballot_access', 'What is the single-subject rule for legislation in Iowa?', '["Can an omnibus bill cover multiple topics in IA?","Single-subject requirement Iowa","Iowa Constitution Article 3 restrictions"]', 'The Iowa Constitution mandates that every act shall embrace but one subject, and matters properly connected therewith, which subject shall be expressed in the title. This prevents unrelated ''riders'' from being attached to legislation.', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article III § 29', '2026-05-13', 'static', 'statute_citation', 'State Legislators and Legal Counsel', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('75ba7f007e21c1e4', 'IA', '["state"]', 'ballot_access', 'How often is a constitutional convention question placed on the Iowa ballot?', '["Constitutional convention referendum Iowa","When can voters call a convention in IA?","Decennial convention question"]', 'Under Article X § 3 of the Iowa Constitution, a question asking voters whether a convention should be called to revise and amend the state constitution must automatically appear on the general election ballot every 10 years ending in zero (e.g., 2020, 2030).', 'https://www.legis.iowa.gov/docs/publications/Constitution/Constitution_of_the_State_of_Iowa_2023.pdf', 'Iowa Constitution Article X § 3', '2026-05-13', 'static', 'statute_citation', 'Ballot measure committees and Strategists', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('51bb3a724e2afdf5', 'IA', '["municipal"]', 'election_dates', 'Are mayoral and city council elections partisan in Iowa?', '["Do mayors run with a party label in IA?","City council partisan elections Iowa","Municipal election structure"]', 'No. The vast majority of mayoral and city council elections in Iowa, including in large cities like Des Moines, are strictly nonpartisan. Candidates appear on the ballot without a political party affiliation.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State', '2026-05-13', 'static', 'official_source_direct', 'Municipal candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1'),
  ('f48cfa79f941a591', 'IA', '["special_district","municipal"]', 'election_dates', 'When are local school board elections held in Iowa?', '["School board trustee elections IA","Do school board candidates run with a party label?","Education board election schedule"]', 'Local school board elections in Iowa are nonpartisan and are held in November of odd-numbered years, separating them from the federal and state partisan general election cycle.', 'https://sos.iowa.gov/elections/candidates/index.html', 'Iowa Secretary of State', '2026-05-13', 'static', 'official_source_direct', 'School Board candidates', 'batch_2026-05-13T15-56-43_iowa_full_v1')
